const d = $input.first().json;

const systemPrompt = `You are an independent crypto technical analyst with no buy or sell bias.

Task: Objectively analyze all provided technical data and give a short-term trading recommendation on the 4H timeframe.

Mandatory analysis process — follow this exact order:
1. List all BEARISH signals currently present
2. List all BULLISH signals currently present
3. Assess the level of conflict between the two signal groups
4. Determine which signals are more reliable based on volume and price action
5. Conclude with signal and score

Scoring rules (score 1–10):
- Start from 5 (neutral)
- Each clear confirming technical signal: +1
- Each signal conflicting with the conclusion: -0.5
- Low volume (volRatio < 0.7) on any signal: reduce confidence, do not add points for that signal
- Final score must reflect the actual level of consensus, no rounding up

Daily Trend rules — use as context only, not as a command:
- STRONG_UPTREND/UPTREND: A pullback in an uptrend may be a buy opportunity, but only if 4H signals confirm. If 4H is still weak, HOLD and wait, do not rush to BUY.
- STRONG_DOWNTREND/DOWNTREND: A bounce in a downtrend is usually not sustainable; very strong 4H signals are needed to consider BUY.
- RSI Daily > 75: Coin has surged, high correction risk — increase riskLevel by one tier above initial assessment.
- RSI Daily < 30: Coin is oversold — BUY signals benefit from context, but still need 4H confirmation.

No-entry rules — return HOLD if any of the following are true:
- Low volume (volRatio < 0.6) combined with weak price action (THREE_BLACK_CROWS, SHOOTING_STAR, DOJI)
- Bullish and bearish signals are roughly balanced (no clear dominant group)
- MACD histogram negative + no crossover + price not in oversold zone

Output requirements:
- confidence must reflect the actual consensus level among signals
- If score < 6: signal must be HOLD or needs a very compelling reason to differ
- If many conflicting signals: confidence must not exceed 0.65
- Return ONLY valid JSON, no text or markdown outside`;

const userPrompt = `Analyze the following coin using the exact 5-step process from the system prompt.

SYMBOL: ${d.symbol}

Basic info:
Current price:   ${d.price} USDT
24h Change:      ${d.change24h}%
24h Volume:      ${d.volume24h.toLocaleString()} USDT

Daily trend (macro context):
Daily Trend:     ${d.dailyTrend}
EMA20 Daily:     ${d.ema20D} | EMA50 Daily: ${d.ema50D}
EMA Slope:       ${d.emaSlope}
RSI Daily:       ${d.rsi1D}${d.rsi1D > 75 ? ' ⚠️ Overbought — increase riskLevel by one tier' : d.rsi1D < 30 ? ' ⚠️ Oversold' : ''}

4H trend:
EMA20 / EMA50:   ${d.ema20} / ${d.ema50} → ${d.ema20 > d.ema50 ? 'EMA20 above EMA50 (4H bullish)' : 'EMA20 below EMA50 (4H bearish)'}
RSI-14 (4H):     ${d.rsi14}${d.rsi14 > 70 ? ' (Overbought)' : d.rsi14 < 30 ? ' (Oversold)' : ' (Neutral)'}
Last 10 candles:  ${d.closes.join(' → ')}

Momentum:
MACD Line:       ${d.macdLine}
MACD Signal:     ${d.macdSignal}
MACD Histogram:  ${d.macdHistogram}${d.macdHistogram > 0 ? ' (accelerating)' : ' (decelerating)'}
MACD Crossover:  ${d.macdCrossover}

Volatility & Price position:
BB Upper:        ${d.bbUpper}
BB Middle:       ${d.bbMiddle}
BB Lower:        ${d.bbLower}
BB Width:        ${d.bbWidth}%${d.bbWidth < 5 ? ' ⚠️ Squeeze' : ''}
BB Position:     ${d.bbPos}%${d.bbPos > 80 ? ' (near upper band)' : d.bbPos < 20 ? ' (near lower band)' : ''}
Position/20 candles: ${d.posInRange}% (0%=low, 100%=high)
High 20 candles: ${d.recent20H} | Low 20 candles: ${d.recent20L}

Volume:
Volume ratio:    ${d.volRatio}x${d.volRatio < 0.7 ? ' ⚠️ Low — reduce signal confidence' : d.volRatio > 1.5 ? ' (High — confirms signal)' : ''}
Buying vol %:    ${d.buyVolPct}%${d.buyVolPct > 60 ? ' (buying pressure)' : d.buyVolPct < 40 ? ' (selling pressure)' : ' (balanced)'}
Volume context:  ${d.volContext}

Price Action:
Current candle:  ${d.candlePattern}
3-candle pattern: ${d.multiPattern}

Order Book:
Buy pressure:    ${d.bookPressure}%${d.bookPressure > 55 ? ' (buyers stronger)' : d.bookPressure < 45 ? ' (sellers stronger)' : ' (balanced)'}

Return JSON in the exact format below, DO NOT add any text outside JSON:
{
  "signal":            "BUY | SELL | HOLD",
  "score":             <1.0–10.0>,
  "entry":             <entry price, null if HOLD>,
  "stopLoss":          <SL price 2–5% from entry, null if HOLD>,
  "takeProfit":        <TP price with R:R min 1:2, null if HOLD>,
  "reason":            "<summary of main reason under 100 words>",
  "conflictingSignals":"<list conflicting signals with conclusion, or 'none'>",
  "riskLevel":         "LOW | MEDIUM | HIGH",
  "confidence":        <0.0–1.0>
}`;

return [{
  json: {
    ...d,
    systemPrompt,
    userPrompt,
  }
}];

// ── Get all candles from input ──────────────────────────────────
const allItems = $input.all();
const candles = allItems.map(item => {
  const c = item.json;
  return {
    openTime: new Date(Number(c[0])).toLocaleString("vi-VN", { timeZone: "Asia/Ho_Chi_Minh" }),
    open:     parseFloat(c[1]),
    high:     parseFloat(c[2]),
    low:      parseFloat(c[3]),
    close:    parseFloat(c[4]),
    volume:   parseFloat(c[5]),
    trades:   Number(c[8])
  };
});

const closes  = candles.map(c => c.close);
const volumes = candles.map(c => c.volume);
const highs   = candles.map(c => c.high);
const lows    = candles.map(c => c.low);

// ── RSI-14 ────────────────────────────────────────────────────
function calcRSI(arr, period = 14) {
  let gains = 0, losses = 0;
  for (let i = arr.length - period; i < arr.length; i++) {
    const d = arr[i] - arr[i - 1];
    d > 0 ? (gains += d) : (losses += Math.abs(d));
  }
  const rs = (gains / period) / (losses / period || 0.0001);
  return parseFloat((100 - 100 / (1 + rs)).toFixed(2));
}

// ── EMA (returns full array) ────────────────────────────────
function calcEMAArr(arr, period) {
  const k = 2 / (period + 1);
  let ema = arr.slice(0, period).reduce((a, b) => a + b) / period;
  const result = new Array(period - 1).fill(null); // padding cho đủ độ dài
  result.push(ema);
  for (let i = period; i < arr.length; i++) {
    ema = arr[i] * k + ema * (1 - k);
    result.push(ema);
  }
  return result;
}

// ── EMA (returns last value) ────────────────────────────────
function calcEMA(arr, period) {
  const full = calcEMAArr(arr, period);
  return parseFloat(full[full.length - 1].toFixed(4));
}

// ── Full MACD: Line, Signal, Histogram, Crossover ──────────
function calcMACD(closes) {
  const ema12arr = calcEMAArr(closes, 12);
  const ema26arr = calcEMAArr(closes, 26);

  // Calculate MACD line at positions where ema26 has value (not null)
  const macdLine = [];
  for (let i = 0; i < ema26arr.length; i++) {
    if (ema26arr[i] === null || ema12arr[i] === null) {
      macdLine.push(null);
    } else {
      macdLine.push(ema12arr[i] - ema26arr[i]);
    }
  }

  // Filter out nulls to calculate Signal Line (EMA9 of MACD line)
  const macdValid = macdLine.filter(v => v !== null);
  const signalArr = calcEMAArr(macdValid, 9);

  const lastMACD    = macdValid[macdValid.length - 1];
  const prevMACD    = macdValid[macdValid.length - 2];
  const lastSignal  = signalArr[signalArr.length - 1];
  const prevSignal  = signalArr[signalArr.length - 2];
  const histogram   = lastMACD - lastSignal;

  // Detect crossover at current candle
  let crossover = 'NONE';
  if (prevMACD !== null && prevSignal !== null) {
    if (prevMACD < prevSignal && lastMACD > lastSignal) crossover = 'BULLISH';
    if (prevMACD > prevSignal && lastMACD < lastSignal) crossover = 'BEARISH';
  }

  return {
    macdLine:  parseFloat(lastMACD.toFixed(4)),
    signal:    parseFloat(lastSignal.toFixed(4)),
    histogram: parseFloat(histogram.toFixed(4)),
    crossover,
  };
}

// ── Bollinger Bands ───────────────────────────────────────────
function calcBollinger(closes, period = 20, mult = 2) {
  const slice = closes.slice(-period);
  const mean  = slice.reduce((a, b) => a + b) / period;
  const std   = Math.sqrt(slice.reduce((s, v) => s + (v - mean) ** 2, 0) / period);
  const upper = mean + mult * std;
  const lower = mean - mult * std;
  const price = closes[closes.length - 1];

  return {
    bbUpper:  parseFloat(upper.toFixed(4)),
    bbMiddle: parseFloat(mean.toFixed(4)),
    bbLower:  parseFloat(lower.toFixed(4)),
    bbWidth:  parseFloat(((upper - lower) / mean * 100).toFixed(2)), // % — <5% = squeeze
    bbPos:    parseFloat(((price - lower) / (upper - lower) * 100).toFixed(1)), // 0–100%
  };
}

// ── Volume analysis — distinguish buying vs selling volume ─────
function calcVolumeAnalysis(candles, period = 20) {
  const recent = candles.slice(-period);
  let buyVol = 0, sellVol = 0;
  recent.forEach(c => {
    if (c.close >= c.open) buyVol  += c.volume;
    else                   sellVol += c.volume;
  });
  const total     = buyVol + sellVol;
  const buyVolPct = parseFloat((buyVol / total * 100).toFixed(1));

  const recentVol = candles[candles.length - 1].volume;
  const avgVol    = recent.reduce((s, c) => s + c.volume, 0) / period;
  const volRatio  = parseFloat((recentVol / avgVol).toFixed(2));

  const lastCandle   = candles[candles.length - 1];
  const isBullishBar = lastCandle.close >= lastCandle.open;
  const volContext   =
    volRatio >= 1.5 ? (isBullishBar ? 'HIGH_BUY_VOL' : 'HIGH_SELL_VOL') :
    volRatio <= 0.7 ? 'LOW_VOL' : 'NORMAL_VOL';

  return { buyVolPct, volRatio, volContext };
}

// ── Candle pattern — look at 3 candles ──────────────────────────────
function calcCandleContext(candles) {
  const last3    = candles.slice(-3);
  const [c1, c2, c3] = last3;
  const { open: o, high: h, low: l, close: c } = c3;
  const body       = Math.abs(c - o);
  const totalRange = (h - l) || 0.0001;
  const upperWick  = h - Math.max(o, c);
  const lowerWick  = Math.min(o, c) - l;

  // Single candle pattern
  let candlePattern = c > o ? 'BULLISH' : 'BEARISH';
  if (lowerWick > body * 2 && lowerWick > upperWick)  candlePattern = 'HAMMER';
  else if (upperWick > body * 2 && upperWick > lowerWick) candlePattern = 'SHOOTING_STAR';
  else if (body < totalRange * 0.1)                    candlePattern = 'DOJI';

  // 3-candle pattern
  const allBullish = last3.every(x => x.close > x.open);
  const allBearish = last3.every(x => x.close < x.open);
  const prev2Down  = c1.close < c1.open && c2.close < c2.open;
  const prev2Up    = c1.close > c1.open && c2.close > c2.open;

  let multiPattern = 'NONE';
  if (allBullish && c3.close > c2.close && c2.close > c1.close)
    multiPattern = 'THREE_WHITE_SOLDIERS';
  else if (allBearish && c3.close < c2.close && c2.close < c1.close)
    multiPattern = 'THREE_BLACK_CROWS';
  else if (prev2Down && candlePattern === 'HAMMER')
    multiPattern = 'HAMMER_AFTER_DECLINE';
  else if (prev2Up && candlePattern === 'SHOOTING_STAR')
    multiPattern = 'STAR_AFTER_RALLY';

  return { candlePattern, multiPattern };
}

// ── Price structure ─────────────────────────────────────────────
function calcPriceStructure(closes, highs, lows) {
  const recent20H  = Math.max(...highs.slice(-20));
  const recent20L  = Math.min(...lows.slice(-20));
  const price      = closes[closes.length - 1];
  const posInRange = parseFloat(
    ((price - recent20L) / (recent20H - recent20L) * 100).toFixed(1)
  );
  return { recent20H, recent20L, posInRange };
}

// ── Call all functions ───────────────────────────────────────────────
const macdData   = calcMACD(closes);
const bbData     = calcBollinger(closes);
const volData    = calcVolumeAnalysis(candles);
const candleData = calcCandleContext(candles);
const structure  = calcPriceStructure(closes, highs, lows);

return [{
  json: {
    // Core indicators
    rsi14:  calcRSI(closes),
    ema20:  calcEMA(closes, 20),
    ema50:  calcEMA(closes, 50),
    closes: closes.slice(-10),

    // Full MACD
    macdLine:      macdData.macdLine,
    macdSignal:    macdData.signal,
    macdHistogram: macdData.histogram,
    macdCrossover: macdData.crossover,

    // Bollinger Bands
    bbUpper:  bbData.bbUpper,
    bbMiddle: bbData.bbMiddle,
    bbLower:  bbData.bbLower,
    bbWidth:  bbData.bbWidth,
    bbPos:    bbData.bbPos,

    // Directional volume analysis
    volRatio:   volData.volRatio,
    buyVolPct:  volData.buyVolPct,
    volContext: volData.volContext,

    // Single and 3-candle patterns
    candlePattern: candleData.candlePattern,
    multiPattern:  candleData.multiPattern,

    // Price structure
    recent20H:  structure.recent20H,
    recent20L:  structure.recent20L,
    posInRange: structure.posInRange,
  }
}];

const depth = $input.first().json;

// bids and asks: [["price", "qty"], ...]
const bidVol = depth.bids.slice(0, 5)
  .reduce((s, b) => s + parseFloat(b[1]), 0);
const askVol = depth.asks.slice(0, 5)
  .reduce((s, a) => s + parseFloat(a[1]), 0);

return [{
  json: {
    bookPressure: parseFloat((bidVol / (bidVol + askVol) * 100).toFixed(1)),
  }
}];

const all = $input.all().map(i => i.json);

const klineData  = all.find(o => o.rsi14        !== undefined) ?? {};
const tickerData = all.find(o => o.lastPrice     !== undefined) ?? {};
const bookData   = all.find(o => o.bookPressure  !== undefined) ?? {};
const dailyData  = all.find(o => o.dailyTrend !== undefined) ?? {};

return [{
  json: {
    // ── Ticker ──────────────────────────────────────────────
    symbol:    tickerData.symbol,
    price:     parseFloat(tickerData.lastPrice),
    change24h: parseFloat(tickerData.priceChangePercent),
    volume24h: parseFloat(tickerData.quoteVolume),

    // ── Core indicators ─────────────────────────────────────────
    rsi14:  klineData.rsi14,
    ema20:  klineData.ema20,
    ema50:  klineData.ema50,
    closes: klineData.closes,

    // ── Full MACD ─────────────────────────────────────────
    macdLine:      klineData.macdLine,
    macdSignal:    klineData.macdSignal,
    macdHistogram: klineData.macdHistogram,
    macdCrossover: klineData.macdCrossover,

    // ── Bollinger Bands ──────────────────────────────────────
    bbUpper:  klineData.bbUpper,
    bbMiddle: klineData.bbMiddle,
    bbLower:  klineData.bbLower,
    bbWidth:  klineData.bbWidth,
    bbPos:    klineData.bbPos,

    // ── Directional volume analysis ───────────────────────────────
    volRatio:   klineData.volRatio,
    buyVolPct:  klineData.buyVolPct,
    volContext: klineData.volContext,

    // ── Single and 3-candle patterns ────────────────────────────
    candlePattern: klineData.candlePattern,
    multiPattern:  klineData.multiPattern,

    // ── Price structure ────────────────────────────────────────
    recent20H:  klineData.recent20H,
    recent20L:  klineData.recent20L,
    posInRange: klineData.posInRange,

    // ── Order Book ───────────────────────────────────────────
    bookPressure: bookData.bookPressure,

    // ── Daily Trend ─────────────────────────────────────────
    dailyTrend: dailyData.dailyTrend,
    ema20D:     dailyData.ema20D,
    ema50D:     dailyData.ema50D,
    emaSlope:   dailyData.emaSlope,
    rsi1D:      dailyData.rsi1D,
  }
}];

// ── Get all daily candles from input ───────────────────────────
const allItems = $input.all();
const candles  = allItems.map(item => {
  const c = item.json;
  return {
    open:   parseFloat(c[1]),
    high:   parseFloat(c[2]),
    low:    parseFloat(c[3]),
    close:  parseFloat(c[4]),
    volume: parseFloat(c[5]),
  };
});

const closes = candles.map(c => c.close);

// ── Full EMA array ─────────────────────────────────────────
function calcEMAArr(arr, period) {
  if (arr.length < period) return new Array(arr.length).fill(null);
  const k      = 2 / (period + 1);
  let ema      = arr.slice(0, period).reduce((a, b) => a + b) / period;
  const result = new Array(period - 1).fill(null);
  result.push(ema);
  for (let i = period; i < arr.length; i++) {
    ema = arr[i] * k + ema * (1 - k);
    result.push(ema);
  }
  return result;
}

function calcEMA(arr, period) {
  const full = calcEMAArr(arr, period);
  const last  = full[full.length - 1];
  return last !== null ? parseFloat(last.toFixed(4)) : null;
}

// ── Calculate EMA20D and EMA50D ─────────────────────────────────────
const ema20D = calcEMA(closes, 20);
const ema50D = calcEMA(closes, 50);
const price  = closes[closes.length - 1];

// ── Slope EMA20: compare current value vs 5 candles ago ─────
// Use array to get EMA20 value at 5 candles ago position
const ema20Arr    = calcEMAArr(closes, 20);
const ema20Now    = ema20Arr[ema20Arr.length - 1];
const ema20_5ago  = ema20Arr[ema20Arr.length - 6]; // 5 nến trước
const emaSlope    = (ema20Now !== null && ema20_5ago !== null)
  ? (ema20Now > ema20_5ago ? 'RISING' : 'FALLING')
  : 'UNKNOWN';

// ── Determine daily trend ───────────────────────────────────
let dailyTrend = 'SIDEWAYS';
if (ema20D !== null && ema50D !== null) {
  if      (price > ema20D && ema20D > ema50D && emaSlope === 'RISING')  dailyTrend = 'STRONG_UPTREND';
  else if (price > ema20D && emaSlope === 'RISING')                      dailyTrend = 'UPTREND';
  else if (price < ema20D && ema20D < ema50D && emaSlope === 'FALLING') dailyTrend = 'STRONG_DOWNTREND';
  else if (price < ema20D && emaSlope === 'FALLING')                     dailyTrend = 'DOWNTREND';
}

// ── RSI Daily (14) for additional context ───────────────────────
function calcRSI(arr, period = 14) {
  if (arr.length < period + 1) return null;
  let gains = 0, losses = 0;
  for (let i = arr.length - period; i < arr.length; i++) {
    const d = arr[i] - arr[i - 1];
    d > 0 ? (gains += d) : (losses += Math.abs(d));
  }
  const rs = (gains / period) / (losses / period || 0.0001);
  return parseFloat((100 - 100 / (1 + rs)).toFixed(2));
}

return [{
  json: {
    dailyTrend,
    ema20D,
    ema50D,
    emaSlope,
    rsi1D: calcRSI(closes),
  }
}];

const raw = $input.first().json;

const text = raw.output[0].content[0].text;
console.log(text);

let analysis;
try {
  const cleaned = text.replace(/```json|```/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch (e) {
  analysis = {
    signal:     'HOLD',
    score:      0,
    entry:      null,
    stopLoss:   null,
    takeProfit: null,
    reason:     'JSON parse error from AI: ' + e.message,
    riskLevel:  'HIGH',
    confidence: 0,
  };
}

const origin = $('Construct AI Analysis Prompt').first().json;

return [{
  json: {
    symbol:      origin.symbol,
    price:       origin.price,
    change24h:   origin.change24h,
    signal:      analysis.signal,
    score:       analysis.score,
    entry:       analysis.entry,
    stopLoss:    analysis.stopLoss,
    takeProfit:  analysis.takeProfit,
    reason:      analysis.reason,
    conflictingSignals: analysis.conflictingSignals ?? null,
    riskLevel:   analysis.riskLevel,
    confidence:  analysis.confidence ?? null,
    lastUpdated: new Date().toISOString(),
  }
}];

const d    = $input.first().json;
const sign = n => n > 0 ? '+' : '';
const pct  = (a, b) => ((a - b) / b * 100).toFixed(2);

const emoji  = d.signal === 'BUY' ? '🟢' : '🔴';
const rsiDailyFlag = d.rsi1D > 75 ? ' ⚠️' : d.rsi1D < 30 ? ' 🔥' : '';

const levels = d.signal !== 'HOLD'
? `
🎯 <b>Entry</b>
<code>${d.entry} USDT</code>

🛑 <b>Stop Loss</b>
<code>${d.stopLoss} USDT</code>  <i>(${pct(d.stopLoss, d.entry)}%)</i>

✅ <b>Take Profit</b>
<code>${d.takeProfit} USDT</code>  <i>(+${pct(d.takeProfit, d.entry)}%)</i>
`
: '';

const conflicts = (d.conflictingSignals && d.conflictingSignals !== 'none')
? `
⚠️ <b>Conflicting Signals</b>
<i>${d.conflictingSignals}</i>
`
: '';

const message = `\
${emoji} <b>${d.signal} – ${d.symbol}</b>
<i>${d.riskLevel} RISK  ·  Score ${d.score}/10  ·  Confidence ${(d.confidence * 100).toFixed(0)}%</i>
━━━━━━━━━━━━━━━━━━━━━

💰 <b>Current Price</b>
<code>${d.price} USDT</code>  <i>(${sign(d.change24h)}${d.change24h}% / 24h)</i>
${levels}
━━━━━━━━━━━━━━━━━━━━━
📊 <b>Key Indicators</b>
├ Daily Trend:  <code>${d.dailyTrend}</code>
├ RSI Daily:    <code>${d.rsi1D}</code>${rsiDailyFlag}
├ RSI 4H:       <code>${d.rsi14}</code>
├ MACD Cross:   <code>${d.macdCrossover}</code>
├ BB Position:  <code>${d.bbPos}%</code>
├ Vol Ratio:    <code>${d.volRatio}x</code>
└ Book Pressure:<code>${d.bookPressure}%</code>
${conflicts}
━━━━━━━━━━━━━━━━━━━━━
📝 <b>Reason</b>
<i>${d.reason}</i>

🕐 ${d.lastUpdated}`;

return [{ json: { message } }];
